// Responsive image
//
// Keep images from scaling beyond the width of their parents.
.img-responsive(@display: block) {
  display: @display;
  max-width: 100%; // Part 1: Set a maximum relative to the parent
  height: auto; // Part 2: Scale the height according to the width, otherwise you get stretching
}


// Retina image
//
// Short retina mixin for setting background-image and -size. Note that the
// spelling of `min--moz-device-pixel-ratio` is intentional.
.img-retina(@file-1x; @file-2x; @width-1x; @height-1x) {
  background-image: url("@{file-1x}");

  @media
  only screen and (-webkit-min-device-pixel-ratio: 2),
  only screen and (   min--moz-device-pixel-ratio: 2),
  only screen and (     -o-min-device-pixel-ratio: 2/1),
  only screen and (        min-device-pixel-ratio: 2),
  only screen and (                min-resolution: 192dpi),
  only screen and (                min-resolution: 2dppx) {
    background-image: url("@{file-2x}");
    background-size: @width-1x @height-1x;
  }
}

@import (reference) '../../style/themes/index';
@input-prefix-cls: ~'@{ant-prefix}-input';

// ========================= Input =========================
.@{iconfont-css-prefix}.@{input-prefix-cls}-clear-icon,
.@{input-prefix-cls}-clear-icon {
  margin: 0;
  color: @disabled-color;
  font-size: @font-size-sm;
  vertical-align: -1px;
  // https://github.com/ant-design/ant-design/pull/18151
  // https://codesandbox.io/s/wizardly-sun-u10br
  cursor: pointer;
  transition: color 0.3s;

  &:hover {
    color: @text-color-secondary;
  }

  &:active {
    color: @text-color;
  }

  &-hidden {
    visibility: hidden;
  }

  &-has-suffix {
    margin: 0 @input-affix-margin;
  }
}

// ======================= TextArea ========================
.@{input-prefix-cls}-affix-wrapper.@{input-prefix-cls}-affix-wrapper-textarea-with-clear-btn {
  padding: 0;

  .@{input-prefix-cls}-clear-icon {
    position: absolute;
    top: 8px;
    right: 8px;
    z-index: 1;
  }
}

@keyframes loadingCircle {
  100% {
    transform: rotate(360deg);
  }
}

@click-animating-true: ~"[@{ant-prefix}-click-animating='true']";
@click-animating-with-extra-node-true: ~"[@{ant-prefix}-click-animating-without-extra-node='true']";

@{click-animating-true},
@{click-animating-with-extra-node-true} {
  position: relative;
}

html {
  --antd-wave-shadow-color: @primary-color;
  --scroll-bar: 0;
}

@click-animating-with-extra-node-true-after: ~'@{click-animating-with-extra-node-true}::after';

@{click-animating-with-extra-node-true-after},
.@{ant-prefix}-click-animating-node {
  position: absolute;
  top: 0;
  right: 0;
  bottom: 0;
  left: 0;
  display: block;
  border-radius: inherit;
  box-shadow: 0 0 0 0 @primary-color;
  box-shadow: 0 0 0 0 var(--antd-wave-shadow-color);
  opacity: 0.2;
  animation: fadeEffect 2s @ease-out-circ, waveEffect 0.4s @ease-out-circ;
  animation-fill-mode: forwards;
  content: '';
  pointer-events: none;
}

@keyframes waveEffect {
  100% {
    box-shadow: 0 0 0 @primary-color;
    box-shadow: 0 0 0 @wave-animation-width var(--antd-wave-shadow-color);
  }
}

@keyframes fadeEffect {
  100% {
    opacity: 0;
  }
}

@import (reference) '../../style/themes/index';
@menu-prefix-cls: ~'@{ant-prefix}-menu';

.@{menu-prefix-cls} {
  // Danger
  &-item-danger&-item {
    color: @menu-highlight-danger-color;

    &:hover,
    &-active {
      color: @menu-highlight-danger-color;
    }

    &:active {
      background: @menu-item-active-danger-bg;
    }

    &-selected {
      color: @menu-highlight-danger-color;

      > a,
      > a:hover {
        color: @menu-highlight-danger-color;
      }
    }

    .@{menu-prefix-cls}:not(.@{menu-prefix-cls}-horizontal) &-selected {
      background-color: @menu-item-active-danger-bg;
    }

    .@{menu-prefix-cls}-inline &::after {
      border-right-color: @menu-highlight-danger-color;
    }
  }

  // ==================== Dark ====================
  &-dark &-item-danger&-item {
    &,
    &:hover,
    & > a {
      color: @menu-dark-danger-color;
    }
  }

  &-dark&-dark:not(&-horizontal) &-item-danger&-item-selected {
    color: @menu-dark-highlight-color;
    background-color: @menu-dark-item-active-danger-bg;
  }
}

@class-prefix-rate: ~'adm-rate';

.@{class-prefix-rate} {
  --star-size: 24px;
  --active-color: var(--adm-color-yellow);
  --inactive-color: var(--adm-color-border);
  --inactive-color-half: var(--adm-color-border);

  display: inline-flex;
  touch-action: pan-y;
  user-select: none;
  &-box {
    position: relative;
  }

  &-star {
    padding: 0.125em;
    line-height: var(--star-size);
    font-size: var(--star-size);
    color: var(--inactive-color);
    text-align: center;
    overflow: hidden;
    cursor: pointer;
    box-sizing: border-box;
    transition: all 0.3s;
    &-half {
      padding-right: 0;
      width: 50%;
      position: absolute;
      left: 0;
      top: 0;
    }
    &-active {
      color: var(--active-color);
    }
    &-readonly {
      cursor: unset;
    }
  }

  &&-half {
    .@{class-prefix-rate}-star-half:not(.@{class-prefix-rate}-star-active) {
      color: var(--inactive-color-half);
    }
  }
}

@class-prefix-footer: ~'adm-footer';

.@{class-prefix-footer} {
  --background-color: var(--adm-color-background);

  color: var(--adm-color-text);
  display: flex;
  flex-direction: column;
  align-items: center;
  background-color: var(--background-color);

  &-label {
    width: 100%;
    .adm-divider.adm-divider {
      color: var(--adm-color-light);
    }
  }
  &-links {
    margin: 8px 0;
    color: var(--adm-color-primary);
    white-space: nowrap;
    a {
      text-decoration: none;
    }
  }
  &-content {
    display: flex;
    align-items: center;
    margin: 8px 0;
    color: var(--adm-color-light);
  }
  &-chips {
    display: flex;
    align-items: center;
    white-space: nowrap;
    margin: 8px 0;
  }
  &-chip {
    white-space: nowrap;
    margin-right: 20px;
    font-size: 12px;
    background-color: var(--adm-color-fill-content);
    color: var(--adm-color-weak);
    padding: 4px 12px;
    border-radius: 100px;
    &-link {
      cursor: pointer;
      background-color: var(--adm-color-wathet);
      color: var(--adm-color-primary);
    }
    &:last-child {
      margin-right: 0;
    }
  }
}

@class-prefix-center-popup: ~'adm-center-popup';

.@{class-prefix-center-popup} {
  --background-color: var(
    --adm-center-popup-background-color,
    var(--adm-color-background)
  );
  --border-radius: var(--adm-center-popup-border-radius, 8px);
  --max-width: var(--adm-center-popup-max-width, 75vw);
  --min-width: var(--adm-center-popup-min-width, 280px);
  --z-index: var(--adm-center-popup-z-index, 1000);

  position: fixed;
  z-index: var(--z-index);

  .@{class-prefix-center-popup}-mask {
    z-index: 0;
  }
}

.@{class-prefix-center-popup}-wrap {
  position: fixed;
  z-index: 1;
  top: 50%;
  left: 50%;
  width: auto;
  min-width: var(--min-width);
  max-width: var(--max-width);
  transform: translate(-50%, -50%);
}

.@{class-prefix-center-popup}-body {
  background-color: var(--background-color);
  border-radius: var(--border-radius);
}

.@{class-prefix-center-popup}-close {
  position: absolute;
  z-index: 100;
  right: 8px;
  top: 8px;

  cursor: pointer;
  padding: 4px;
  font-size: 18px;
  color: var(--adm-color-weak);
}

@class-prefix-nav-bar: ~'adm-nav-bar';

.@{class-prefix-nav-bar} {
  --height: 45px;
  --border-bottom: none;
  display: flex;
  align-items: center;
  height: var(--height);
  border-bottom: var(--border-bottom);
  padding: 0 12px;
  white-space: nowrap;

  &-left,
  &-right {
    flex: 1;
  }
  &-title {
    flex: auto;
    text-align: center;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  &-back {
    display: flex;
    align-items: center;
    margin-right: 16px;
    padding: 6px 0;
    cursor: pointer;
    &-arrow {
      font-size: 24px;
      margin-right: 4px;
    }
  }

  &-left {
    font-size: var(--adm-font-size-7);
    display: flex;
    justify-content: flex-start;
    align-items: center;
  }

  &-title {
    justify-content: center;
    white-space: nowrap;
    font-size: var(--adm-font-size-10);
    padding: 0 12px;
  }

  &-right {
    text-align: right;
  }
}

// Close icons
// --------------------------------------------------
@prefix-cls-close: e("@{prefix-cls}-close");

@close-font-weight:           bold;
@close-color:                 #000;
@close-text-shadow:           0 1px 0 #fff;

.@{prefix-cls-close} {
  float: right;
  font-size: (@font-size-base * 1.5);
  font-weight: @close-font-weight;
  line-height: 1;
  color: @close-color;
  text-shadow: @close-text-shadow;
  opacity: .2;

  &:hover,
  &:focus {
    color: @close-color;
    text-decoration: none;
    cursor: pointer;
    opacity: .5;
  }

  // Additional properties for button version
  // iOS requires the button element instead of an anchor tag.
  // If you want the anchor version, it requires `href="#"`.
  // See https://developer.mozilla.org/en-US/docs/Web/Events/click#Safari_Mobile
  button& {
    padding: 0;
    cursor: pointer;
    background: transparent;
    border: 0;
    appearance: none;
  }
}

// Breadcrumbs
// --------------------------------------------------
@prefix-cls-breadcrumb: e("@{prefix-cls}-breadcrumb");
@prefix-cls-breadcrumbs: e("@{prefix-cls}-breadcrumbs");

@breadcrumb-link-color: #999999;
@breadcrumb-last-link-color: #666;
@breadcrumb-slash-color: #ccc;

.@{prefix-cls-breadcrumbs} {
  .@{prefix-cls-breadcrumb} {
    padding: 0;
    background-color: #fff;
    .@{prefix-cls-breadcrumb}-link {
      padding: 0 16px;
      color: @breadcrumb-link-color;
      font-size: 12px;
    }
  }

  .@{prefix-cls-breadcrumb}:last-child .@{prefix-cls-breadcrumb}-link {
    color: @breadcrumb-last-link-color;
  }

  .@{prefix-cls-breadcrumb}-symbol {
    color: @breadcrumb-slash-color;
    font-size: 12px;
  }

  span:last-child .@{prefix-cls-breadcrumb}-symbol {
    display: none;
  }
}

// Text
// -------------------

.text-smaller {
  font-size: smaller;
}

.text-subtle    { color: @text-color-subtle; }
.text-highlight { color: @text-color-highlight; }

.text-info    { color: @text-color-info; }
.text-success { color: @text-color-success; }
.text-warning { color: @text-color-warning; }
.text-error   { color: @text-color-error; }


// Highlights ---------------

.highlight         { .highlight-mixin(@background-color-highlight); }
.highlight-info    { .highlight-mixin(@background-color-info); }
.highlight-warning { .highlight-mixin(@background-color-warning); }
.highlight-error   { .highlight-mixin(@background-color-error); }
.highlight-success { .highlight-mixin(@background-color-success); }

.highlight-mixin(@color) {
  padding: 1px 4px;
  color: @text-color-highlight;
  border-radius: @component-border-radius;
  background-color: @color;
}


// Background Message ---------------
// Shown when no tabs are open.

.background-message {
  font-weight: bold;
  color: @text-color-subtle;
}

//
// Jumbotron
// --------------------------------------------------


.jumbotron {
  padding-top:    @jumbotron-padding;
  padding-bottom: @jumbotron-padding;
  margin-bottom: @jumbotron-padding;
  color: @jumbotron-color;
  background-color: @jumbotron-bg;

  h1,
  .h1 {
    color: @jumbotron-heading-color;
  }

  p {
    margin-bottom: (@jumbotron-padding / 2);
    font-size: @jumbotron-font-size;
    font-weight: 200;
  }

  > hr {
    border-top-color: darken(@jumbotron-bg, 10%);
  }

  .container &,
  .container-fluid & {
    border-radius: @border-radius-large; // Only round corners at higher resolutions if contained in a container
    padding-left:  (@grid-gutter-width / 2);
    padding-right: (@grid-gutter-width / 2);
  }

  .container {
    max-width: 100%;
  }

  @media screen and (min-width: @screen-sm-min) {
    padding-top:    (@jumbotron-padding * 1.6);
    padding-bottom: (@jumbotron-padding * 1.6);

    .container &,
    .container-fluid & {
      padding-left:  (@jumbotron-padding * 2);
      padding-right: (@jumbotron-padding * 2);
    }

    h1,
    .h1 {
      font-size: @jumbotron-heading-font-size;
    }
  }
}

